class WebSocketManager {
  private connections: Map<string, WebSocket> = new Map();

  onConnection(ws: WebSocket, userId: string) {
    this.connections.set(userId, ws);
    ws.on('message', (data) => this.handleMessage(userId, data));
  }
}

